// src/utils/normalize-backend.ts
function normalizeBackend(value) {
  const lower = value.toLowerCase();
  if (lower === "appstoreapi" || lower === "appstore-api") {
    return "appstoreApi";
  }
  if (lower === "transporter") {
    return "transporter";
  }
  if (lower === "altool") {
    return "altool";
  }
  throw new Error(
    `Invalid backend '${value}'. Allowed values: appstoreApi | transporter | altool.`
  );
}

// src/main.ts
async function run() {
  try {
    const issuerId = getInput("issuer-id");
    const apiKeyId = getInput("api-key-id");
    const apiPrivateKey = getInput("api-private-key");
    const appPath = getInput("app-path");
    const appType = getInput("app-type");
    const releaseNotes = getInput("release-notes");
    const usesNonExemptEncryptionInput = getInput(
      "uses-non-exempt-encryption"
    );
    const waitForProcessingInput = getInput("wait-for-processing");
    const waitForProcessing = waitForProcessingInput.trim() === "" ? true : waitForProcessingInput.trim().toLowerCase() !== "false";
    const backendInput = getInput("backend") || "appstore-api";
    const transporterExecutablePath = getInput("transporter-executable-path") || void 0;
    const backend = normalizeBackend(backendInput);
    info(
      `Using upload backend: ${backend} for appPath=${appPath}, appType=${appType}`
    );
    const factories = {
      appstoreApi,
      transporter,
      altool
    };
    const uploader = factories[backend];
    if (!uploader) {
      throw new Error(`Unsupported backend ${backend}`);
    }
    if (backend !== "appstoreApi" && platform2() !== "darwin") {
      throw new Error(
        `Backend "${backend}" requires a macOS runner (found ${platform2()}).`
      );
    }
    if (backend === "appstoreApi" && appType.toLowerCase() === "macos") {
      throw new Error(
        'The "appstore-api" backend only supports .ipa uploads. For macOS (.pkg) builds, set backend to "altool" or "transporter".'
      );
    }
    const execOptions = {};
    info("Installing API private key.");
    await installPrivateKey(apiKeyId, apiPrivateKey);
    info("Private key installed.");
    const result = await uploader.upload(
      {
        appPath,
        appType,
        apiKeyId,
        issuerId,
        apiPrivateKey,
        waitForProcessing,
        transporterExecutablePath
      },
      execOptions
    );
    info(`Upload finished via backend: ${result.backend}`);
    await submitBuildMetadataUpdates({
      releaseNotes,
      usesNonExemptEncryptionInput,
      waitForProcessing,
      appPath,
      appType,
      issuerId,
      apiKeyId,
      apiPrivateKey
    });
    info("Release notes step completed (or skipped).");
    await deleteAllPrivateKeys();
    info("Private keys cleaned up.");
    setOutput("upload-backend", result.backend);
  } catch (error2) {
    setFailed(error2.message || "An unknown error occurred.");
  }
}
run();
